sheet.mermaid-diagram:
flowchart TD
%% Nodes A([Content Update Detected]) B[Retrieve Latest Content] C[Parse and Clean HTML] D[Semantic Chunking] E[Generate Embeddings] F[Update Vector Database] G([Synchronization Complete])
%% Flow A --> B B --> C C --> D D --> E E --> F F --> G
%% Styling classDef process fill:#1c5d8c,stroke:#0d2b45,stroke-width:2px,color:#ffffff; classDef highlight fill:#fdf6ea,stroke:#e8a33d,stroke-width:2px,color:#b5791c; classDef startend fill:#0d2b45,stroke:#e8a33d,stroke-width:3px,color:#ffffff;
class A,G startend; class B,C,D process; class E,F highlight; linkStyle default stroke:#0d2b45,stroke-width:2px;

flowchart TD
%% Nodes A([Raw Website Data]) B[Content Extraction] C[Content Cleaning & HTML Parsing] D[Semantic Chunking - 500 Tokens] E[Embedding Generation] F[(Vector Database Indexing)] G([Search-Ready Knowledge Base])
%% Flow A --> B B --> C C --> D D --> E E --> F F --> G
%% Styling classDef process fill:#1c5d8c,stroke:#0d2b45,stroke-width:2px,color:#ffffff; classDef highlight fill:#fdf6ea,stroke:#e8a33d,stroke-width:2px,color:#b5791c; classDef startend fill:#0d2b45,stroke:#e8a33d,stroke-width:3px,color:#ffffff;
class A,G startend; class B,C,D process; class E,F highlight; linkStyle default stroke:#0d2b45,stroke-width:2px;

flowchart TD
%% Nodes A([1. User Submits Query]) B[2. REST API Request Validation & Rate Limiting] C[3. Query Vectorization & Embedding Generation] D[(4. Semantic Vector Search in Database)] E[5. Extract Top-K Relevant Chunks & Metadata] F[6. Assemble Contextual Prompt with AI Guardrails] G[7. LLM Engine Inference & Response Generation] H[8. Confidence & Fallback Validation] I[9. Format Response & Attach Source References] J([10. Render Answer & Links in Web Widget])
%% Flow A --> B B --> C C --> D D --> E E --> F F --> G G --> H H --> I I --> J
%% Styling classDef process fill:#1c5d8c,stroke:#0d2b45,stroke-width:2px,color:#ffffff; classDef highlight fill:#fdf6ea,stroke:#e8a33d,stroke-width:2px,color:#b5791c; classDef startend fill:#0d2b45,stroke:#e8a33d,stroke-width:3px,color:#ffffff;
class A,J startend; class B,C,E,F,H,I process; class D,G highlight; linkStyle default stroke:#0d2b45,stroke-width:2px;

flowchart TD subgraph Client ["Client Layer"] UI["Webflow Chat Widget (JS/CSS)"] end subgraph App ["Application Layer"] N["Nginx Reverse Proxy"] API["FastAPI Backend (Python)"] end subgraph Knowledge ["Knowledge Layer"] EMB["Sentence Transformers"] DB[("Vector DB (Qdrant/PostgreSQL)")] end subgraph Intelligence ["AI Layer"] LLM["Google Gemini / OpenAI"] end
UI <-->|HTTPS REST API| N N <--> API API -->|Text Chunk| EMB EMB -->|Vector| DB API <-->|Prompt context| LLM
classDef process fill:#1c5d8c,stroke:#0d2b45,stroke-width:2px,color:#ffffff; classDef highlight fill:#fdf6ea,stroke:#e8a33d,stroke-width:2px,color:#b5791c; classDef startend fill:#0d2b45,stroke:#e8a33d,stroke-width:3px,color:#ffffff;
class UI highlight; class N,API,EMB,DB process; class LLM startend;

flowchart TD U([User]) subgraph Frontend WF["Webflow Widget"] end subgraph Backend N["Nginx"] API["FastAPI Backend"] PB["Prompt Builder"] end subgraph Knowledge EMB["Sentence Transformers"] DB[(Vector DB)] end subgraph AI LLM["Google Gemini / OpenAI"] end
U -->|Chat Message| WF WF -->|HTTPS| N N --> API API --> EMB EMB --> DB DB -->|Relevant Chunks| PB API -->|User Query| PB PB -->|Final Prompt| LLM LLM --> API API -->|Response| WF WF --> U
classDef process fill:#1c5d8c,stroke:#0d2b45,stroke-width:2px,color:#ffffff; classDef highlight fill:#fdf6ea,stroke:#e8a33d,stroke-width:2px,color:#b5791c; classDef startend fill:#0d2b45,stroke:#e8a33d,stroke-width:3px,color:#ffffff;
class U startend; class WF,N,API,PB process; class EMB,DB,LLM highlight; linkStyle default stroke:#0d2b45,stroke-width:2px;

flowchart TD

%% Nodes
A[Website Chat Widget]
B[FastAPI Backend]
C[(Qdrant / PostgreSQL + pgvector)]
D[Prompt Builder]
E[Gemini API]

%% Flow
A -- REST API Request --> B
B -- Retrieval Engine --> C
C --> D
D --> E
E --> B
B -- JSON Response --> A

%% Styling
classDef process fill:#1c5d8c,stroke:#0d2b45,stroke-width:2px,color:#ffffff;
classDef highlight fill:#fdf6ea,stroke:#e8a33d,stroke-width:2px,color:#b5791c;
classDef startend fill:#0d2b45,stroke:#e8a33d,stroke-width:3px,color:#ffffff;

class A startend;
class B,D process;
class C,E highlight;
linkStyle default stroke:#0d2b45,stroke-width:2px;

flowchart TD

A([User Opens Chatbot])
B[Types Message]
C[JavaScript Widget]
D[POST Request to FastAPI]
E[Backend Processes Query]
F[JSON Response Returned]
G([Response Displayed to User])

A --> B --> C --> D --> E --> F --> G

